#include <bits/stdc++.h>
using namespace std;
const long long maxn=4e5;
long long n,m;
struct Node{
	long long y,nx,ny;
};
vector<Node>a[maxn];
bool vis[maxn];
pair<long long,long long> s[maxn];
void dfs(long long x){
	for(long long i=0;i<a[x].size();i++){
		long long y=a[x][i].y;
		if(vis[y]) continue;
		vis[y]=1;
		s[y].first=s[x].first+a[x][i].nx;
		s[y].second=s[x].second+a[x][i].ny;
		dfs(y);
	}
}
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(long long i=1,x,y,nx,ny;i<=m;i++){
		cin>>x>>y>>nx>>ny;
		a[x].push_back({y,nx,ny}),a[y].push_back({x,-nx,-ny});
	}
	s[1].first=s[1].second=0,vis[1]=1;
	dfs(1);
	for(long long i=1;i<=n;i++){
		if(!vis[i]) cout<<"undecidable\n";
		else cout<<s[i].first<<" "<<s[i].second<<"\n";
	}
	return 0;
}
